import type { PluginEnvOptions } from '../types';
/**
 * Read plugin config. Checks runtime store first, then Cypress.expose() on 15.10+, then Cypress.env(), then Cypress.config('env').
 * So hideCredentials set in config env (or via setPluginConfig) is used to hide credentials from cy.env() in the UI.
 */
export declare function getPluginConfig<K extends keyof PluginEnvOptions>(key: K): PluginEnvOptions[K] | undefined;
/**
 * Set plugin config (for tests/support). Stored in runtime so getPluginConfig always sees it; also syncs to Cypress.expose() or Cypress.env() when available.
 */
export declare function setPluginConfig<K extends keyof PluginEnvOptions>(key: K, value: PluginEnvOptions[K]): void;
